# scripts/check_prr_gate.py
# Called by the CD pipeline before promoting to production.
import yaml, sys
from pathlib import Path
from datetime import date

SERVICE = sys.argv[1]
VERSION = sys.argv[2]
PRR_PATH = Path(f"docs/prr/{SERVICE}-{VERSION}.yaml")

REQUIRED_FUNCTIONS = ["sre", "security", "ai_safety", "legal_privacy", "finance"]

if not PRR_PATH.exists():
    print(f"GATE FAIL: No PRR found at {PRR_PATH}")
    sys.exit(1)

prr = yaml.safe_load(PRR_PATH.read_text())

# Check all required functions have APPROVED status
errors = []
sign_offs = {s["function"].lower().replace(" ", "_").replace("/", "_"): s
             for s in prr.get("sign_offs", [])}

for fn in REQUIRED_FUNCTIONS:
    entry = sign_offs.get(fn)
    if not entry:
        errors.append(f"Missing sign-off from: {fn}")
        continue
    status = entry.get("status", "").upper()
    if status == "CONDITIONAL_APPROVED":
        # Check conditions are all met
        for cond in entry.get("conditions", []):
            if not cond.get("evidence"):
                errors.append(f"{fn}: condition unmet — {cond['item']}")
            elif cond.get("due") and date.fromisoformat(cond["due"]) < date.today():
                errors.append(f"{fn}: condition past due — {cond['item']}")
    elif status != "APPROVED":
        errors.append(f"{fn}: status is {status!r} (need APPROVED)")

# Check open items are not past due
for item in prr.get("open_items", []):
    if item.get("due") and date.fromisoformat(item["due"]) < date.today():
        if not item.get("closed"):
            errors.append(f"Open item past due: {item['item']}")

if errors:
    for e in errors: print(f"GATE FAIL: {e}")
    sys.exit(1)

print(f"PRR gate passed for {SERVICE} v{VERSION}. Launch approved.")
